2146 static Value *
2147 simplifyDemandedFPClassMinMax(KnownFPClass &Known, Intrinsic::ID IID,
2148                               const CallInst *CI, FPClassTest DemandedMask,
2149                               KnownFPClass KnownLHS, KnownFPClass KnownRHS,
2150                               const Function &F, bool NSZ) {
2151   bool OrderedZeroSign = !NSZ;
