2159     // operand unless the other is a nan.
2160     if (cannotOrderStrictlyLess(KnownLHS.KnownFPClasses,
2161                                 KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2162         KnownRHS.isKnownNever(fcNan))
2163       return CI->getArgOperand(0);
2164 
2165     if (cannotOrderStrictlyGreater(KnownLHS.KnownFPClasses,
2166                                    KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2167         KnownLHS.isKnownNever(fcNan))
2168       return CI->getArgOperand(1);
2169 
2170     break;
2171   }
2172   case Intrinsic::minimum: {
2173     OpKind = KnownFPClass::MinMaxKind::minimum;
2174 
2175     // If one operand is known less than the other, it must be that operand
2176     // unless the other is a nan.
2177     if (cannotOrderStrictlyGreater(KnownLHS.KnownFPClasses,
2178                                    KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2179         KnownRHS.isKnownNever(fcNan))
2180       return CI->getArgOperand(0);
2181 
2182     if (cannotOrderStrictlyLess(KnownLHS.KnownFPClasses,
2183                                 KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2184         KnownLHS.isKnownNever(fcNan))
2185       return CI->getArgOperand(1);
2186 
2187     break;
2188   }
2189   case Intrinsic::maximumnum: {
2190     OpKind = KnownFPClass::MinMaxKind::maximumnum;
2191 
2192     if (cannotOrderStrictlyLess(KnownLHS.KnownFPClasses,
2193                                 KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2194         KnownLHS.isKnownNever(fcNan))
2195       return CI->getArgOperand(0);
2196 
2197     if (cannotOrderStrictlyGreater(KnownLHS.KnownFPClasses,
2198                                    KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2199         KnownRHS.isKnownNever(fcNan))
2200       return CI->getArgOperand(1);
2201 
2202     break;
2203   }
2204   case Intrinsic::minimumnum: {
2205     OpKind = KnownFPClass::MinMaxKind::minimumnum;
2206 
2207     if (cannotOrderStrictlyGreater(KnownLHS.KnownFPClasses,
2208                                    KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2209         KnownLHS.isKnownNever(fcNan))
2210       return CI->getArgOperand(0);
2211 
2212     if (cannotOrderStrictlyLess(KnownLHS.KnownFPClasses,
2213                                 KnownRHS.KnownFPClasses, OrderedZeroSign) &&
2214         KnownRHS.isKnownNever(fcNan))
