2232 static Value *
2233 simplifyDemandedUseFPClassFPTrunc(InstCombinerImpl &IC, Instruction &I,
2234                                   FastMathFlags FMF, FPClassTest DemandedMask,
2235                                   KnownFPClass &Known, unsigned Depth) {
2236 
2237   FPClassTest SrcDemandedMask = DemandedMask;
2238 
2239   // Zero results may have been rounded from subnormal or normal sources.
2240   if (DemandedMask & fcNegZero)
2241     SrcDemandedMask |= fcNegSubnormal | fcNegNormal;
2242   if (DemandedMask & fcPosZero)
2243     SrcDemandedMask |= fcPosSubnormal | fcPosNormal;
2244 
2245   // Subnormal results may have been normal in the source type
2246   if (DemandedMask & fcNegSubnormal)
2247     SrcDemandedMask |= fcNegNormal;
2248   if (DemandedMask & fcPosSubnormal)
2249     SrcDemandedMask |= fcPosNormal;
2250 
2251   if (DemandedMask & fcPosInf)
2252     SrcDemandedMask |= fcPosNormal;
2253   if (DemandedMask & fcNegInf)
2254     SrcDemandedMask |= fcNegNormal;
2255 
2256   KnownFPClass KnownSrc;
2257   if (IC.SimplifyDemandedFPClass(&I, 0, SrcDemandedMask, KnownSrc, Depth + 1))
2258     return &I;
2259 
2260   Known = KnownFPClass::fptrunc(KnownSrc);
2261   Known.knownNot(~DemandedMask);
2262 
2263   return simplifyDemandedFPClassResult(&I, FMF, DemandedMask, Known,
2264                                        {KnownSrc});
2265 }
