2267 Value *InstCombinerImpl::SimplifyDemandedUseFPClass(Instruction *I,
2268                                                     FPClassTest DemandedMask,
2269                                                     KnownFPClass &Known,
2270                                                     Instruction *CxtI,
2271                                                     unsigned Depth) {
2272   assert(Depth <= MaxAnalysisRecursionDepth && "Limit Search Depth");
2273   assert(Known == KnownFPClass() && "expected uninitialized state");
2274   assert(I->hasOneUse() && "wrong version called");
2275 
2276   Type *VTy = I->getType();
2277 
2278   FastMathFlags FMF;
2279   if (auto *FPOp = dyn_cast<FPMathOperator>(I)) {
2280     FMF = FPOp->getFastMathFlags();
2281     DemandedMask = adjustDemandedMaskFromFlags(DemandedMask, FMF);
2282   }
2283 
2284   switch (I->getOpcode()) {
2285   case Instruction::FNeg: {
2286     // Special case fneg(fabs(x))
2287 
2288     Value *FNegSrc = I->getOperand(0);
2289     Value *FNegFAbsSrc;
2290     if (match(FNegSrc, m_OneUse(m_FAbs(m_Value(FNegFAbsSrc))))) {
2291       KnownFPClass KnownSrc;
2292       if (SimplifyDemandedFPClass(cast<Instruction>(FNegSrc), 0,
2293                                   llvm::unknown_sign(DemandedMask), KnownSrc,
2294                                   Depth + 1))
2295         return I;
2296 
2297       FastMathFlags FabsFMF = cast<FPMathOperator>(FNegSrc)->getFastMathFlags();
2298       FPClassTest ThisDemandedMask =
2299           adjustDemandedMaskFromFlags(DemandedMask, FabsFMF);
2300 
2301       bool IsNSZ = FMF.noSignedZeros() || FabsFMF.noSignedZeros();
2302       if (Value *Simplified = simplifyDemandedFPClassFnegFabs(
2303               Known, FNegFAbsSrc, ThisDemandedMask, KnownSrc, IsNSZ))
2304         return Simplified;
2305 
2306       if ((ThisDemandedMask & fcNan) == fcNone)
2307         KnownSrc.knownNot(fcNan);
2308       if ((ThisDemandedMask & fcInf) == fcNone)
2309         KnownSrc.knownNot(fcInf);
2310 
2311       // fneg(fabs(x)) => fneg(x)
2312       if (KnownSrc.SignBit == false)
2313         return replaceOperand(*I, 0, FNegFAbsSrc);
2314 
2315       // fneg(fabs(x)) => fneg(x), ignoring -0 if nsz.
2316       if (IsNSZ &&
2317           KnownSrc.isKnownNever(KnownFPClass::OrderedLessThanZeroMask | fcNan))
2318         return replaceOperand(*I, 0, FNegFAbsSrc);
2319 
2320       break;
2321     }
2322 
2323     if (SimplifyDemandedFPClass(I, 0, llvm::fneg(DemandedMask), Known,
2324                                 Depth + 1))
2325       return I;
2326     Known.fneg();
2327     Known.knownNot(~DemandedMask);
2328     break;
2329   }
2330   case Instruction::FAdd:
2331   case Instruction::FSub: {
2332     KnownFPClass KnownLHS, KnownRHS;
2333 
2334     // fadd x, x can be handled more aggressively.
2335     if (I->getOperand(0) == I->getOperand(1) &&
2336         I->getOpcode() == Instruction::FAdd &&
2337         isGuaranteedNotToBeUndef(I->getOperand(0), SQ.AC, CxtI, SQ.DT,
2338                                  Depth + 1)) {
2339       Type *EltTy = VTy->getScalarType();
2340       DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());
2341 
2342       FPClassTest SrcDemandedMask = DemandedMask;
2343 
2344       // Doubling a subnormal could have resulted in a normal value.
2345       if (DemandedMask & fcPosNormal)
2346         SrcDemandedMask |= fcPosSubnormal;
2347       if (DemandedMask & fcNegNormal)
2348         SrcDemandedMask |= fcNegSubnormal;
2349 
2350       // Doubling a subnormal may produce 0 if FTZ/DAZ.
2351       if (Mode != DenormalMode::getIEEE()) {
2352         if (DemandedMask & fcPosZero) {
2353           SrcDemandedMask |= fcPosSubnormal;
2354 
2355           if (Mode.inputsMayBePositiveZero() || Mode.outputsMayBePositiveZero())
