2357         }
2358 
2359         if (DemandedMask & fcNegZero)
2360           SrcDemandedMask |= fcNegSubnormal;
2361       }
2362 
2363       // Doubling a normal could have resulted in an infinity.
2364       if (DemandedMask & fcPosInf)
2365         SrcDemandedMask |= fcPosNormal;
2366       if (DemandedMask & fcNegInf)
2367         SrcDemandedMask |= fcNegNormal;
