3436 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3437                                                FPClassTest DemandedMask,
3438                                                KnownFPClass &Known,
3439                                                unsigned Depth) {
3440   Use &U = I->getOperandUse(OpNo);
