3444   if (DemandedMask == fcNone) {
3445     if (isa<PoisonValue>(V))
3446       return false;
3447     replaceUse(U, PoisonValue::get(VTy));
3448     return true;
3449   }
3450 
3451   // Handle constant
3452   Instruction *VInst = dyn_cast<Instruction>(V);
3453   if (!VInst) {
3454     // Handle constants and arguments
3455     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3456     Known.knownNot(~DemandedMask);
3457 
3458     if (Known.KnownFPClasses == fcNone) {
3459       if (isa<PoisonValue>(V))
3460         return false;
3461       replaceUse(U, PoisonValue::get(VTy));
3462       return true;
3463     }
3464 
3465     // Do not try to replace values which are already constants (unless we are
3466     // folding to poison). Doing so could promote poison elements to non-poison
3467     // constants.
3468     if (isa<Constant>(V))
3469       return false;
3470 
3471     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3472     if (!FoldedToConst || FoldedToConst == V)
3473       return false;
