3475     replaceUse(U, FoldedToConst);
3476     return true;
3477   }
3478 
3479   if (const CallBase *CB = dyn_cast<CallBase>(VInst)) {
3480     FPClassTest NoFPClass = CB->getParamNoFPClass(U.getOperandNo());
3481     DemandedMask &= ~NoFPClass;
3482   }
3483 
3484   if (Depth == MaxAnalysisRecursionDepth) {
3485     Known.knownNot(~DemandedMask);
3486     return false;
3487   }
3488 
3489   Value *NewVal;
3490 
3491   if (VInst->hasOneUse()) {
3492     // If the instruction has one use, we can directly simplify it.
3493     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3494   } else {
3495     // If there are multiple uses of this instruction, then we can simplify
3496     // VInst to some other value, but not modify the instruction.
3497     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3498                                                 Depth);
